installation.script:
#!/bin/bash
set -e
apt-get update
apt-get install -y --no-install-recommends \
    build-essential wget tar ca-certificates libssl-dev zlib1g-dev

cd /tmp
wget -q https://sourceforge.net/projects/pcre/files/pcre/8.45/pcre-8.45.tar.gz
tar xzf pcre-8.45.tar.gz

wget -q https://nginx.org/download/nginx-1.26.1.tar.gz
tar xzf nginx-1.26.1.tar.gz
cd nginx-1.26.1

./configure \
    --prefix=/tmp/ngx_prefix \
    --sbin-path=/home/container/bin/nginx \
    --conf-path=/tmp/ngx_prefix/conf/nginx.conf \
    --error-log-path=/home/container/logs/error.log \
    --http-log-path=/home/container/logs/access.log \
    --pid-path=/tmp/nginx.pid \
    --lock-path=/tmp/nginx.lock \
    --http-client-body-temp-path=/tmp/ngx/client \
    --http-proxy-temp-path=/tmp/ngx/proxy \
    --with-pcre=/tmp/pcre-8.45 \
    --without-http_fastcgi_module \
    --without-http_uwsgi_module \
    --without-http_scgi_module \
    --with-http_gzip_static_module

make -j$(nproc)
mkdir -p /mnt/server/bin /mnt/server/logs /mnt/server/webroot
cp objs/nginx /mnt/server/bin/nginx
cp conf/mime.types /mnt/server/bin/mime.types

cat > /mnt/server/webroot/index.html << 'HTMLEOF'
<!DOCTYPE html>
<html lang="fr">
<head>
    <meta charset="UTF-8">
    <title>Nginx Static - Pret</title>
    <style>
        body { font-family: sans-serif; background: #1a1a2e; color: #eee; text-align: center; padding: 80px; }
        h1 { color: #00ff88; }
        code { background: #16213e; padding: 4px 10px; border-radius: 4px; color: #00ff88; }
    </style>
</head>
<body>
    <h1>Nginx Static - Pret</h1>
    <p>Depose tes fichiers dans <code>webroot/</code></p>
</body>
</html>
HTMLEOF

cat > /mnt/server/start.sh << 'STARTEOF'
#!/bin/bash
PORT=${SERVER_PORT:-80}

mkdir -p /tmp/ngx/client /tmp/ngx/proxy /home/container/logs

cat > /tmp/nginx.conf << NGINXEOF
worker_processes 1;
pid /tmp/nginx.pid;
error_log /home/container/logs/error.log warn;

events { worker_connections 512; }

http {
    include /home/container/bin/mime.types;
    default_type application/octet-stream;

    client_body_temp_path /tmp/ngx/client;
    proxy_temp_path       /tmp/ngx/proxy;

    access_log /home/container/logs/access.log;
    sendfile on;
    keepalive_timeout 65;
    gzip on;
    gzip_types text/plain text/css application/javascript application/json image/svg+xml;

    server {
        listen __PORT__;
        root /home/container/webroot;
        index index.html;

        location / { try_files \$uri \$uri/ =404; }

        location ~* \.(css|js|png|jpg|jpeg|gif|ico|svg|woff2|ttf|eot|webp)\$ {
            expires 30d;
            add_header Cache-Control "public, immutable";
        }
    }
}
NGINXEOF

sed -i "s|__PORT__|${PORT}|g" /tmp/nginx.conf

echo "[Nginx] Demarrage sur le port ${PORT}"
exec /home/container/bin/nginx -c /tmp/nginx.conf -g 'daemon off;'
STARTEOF

chmod +x /mnt/server/start.sh
echo "[INSTALL] Termine. Depose tes fichiers dans webroot/"
